#include <stdio.h>
#include <stdlib.h>
#include <inttypes.h>

/*
 * Longest Common Subsequence length via bottom-up DP over two same-length
 * byte buffers, generated by a small-alphabet deterministic formula so real
 * (non-trivial) matches occur. Rolling 2-row storage (O(n) memory, O(n^2)
 * time) rather than a full O(n^2)-memory table: the full table would need
 * gigabytes at the n needed for meaningful timing, and the rolling version is
 * the standard production implementation of the same bottom-up recurrence
 * when only the LCS *length* (not the actual subsequence) is needed.
 */
static int32_t max_i32(int32_t a, int32_t b) {
    return a > b ? a : b;
}

/* splitmix64 (public domain, Vigna) -- a single multiply-mod step (as used
 * in the quicksort benchmark) turned out to have too little avalanche once
 * reduced to a 4-symbol alphabet: (idx * 2654435761) is linear in idx, and
 * low bits/small moduli of a linear congruential step carry visible short
 * periods, causing near-identical buffers (LCS almost n) instead of the
 * random-looking ones a real benchmark needs. splitmix64's xor-shift/multiply
 * finalizer avalanches properly even after `% 4`. */
static uint64_t splitmix64(uint64_t x) {
    x += 0x9E3779B97F4A7C15ULL;
    x = (x ^ (x >> 30)) * 0xBF58476D1CE4E5B9ULL;
    x = (x ^ (x >> 27)) * 0x94D049BB133111EBULL;
    x = x ^ (x >> 31);
    return x;
}

/* Different seed per buffer (not just a shifted index into the same stream)
 * so A and B are independent-looking sequences, not one shifted copy of the
 * other. */
static void fill(uint8_t *buf, int32_t n, uint64_t seed) {
    for (int32_t i = 0; i < n; i++) {
        uint64_t idx = (uint64_t)(i + 1) + seed;
        buf[i] = (uint8_t)('A' + (splitmix64(idx) % 4));
    }
}

static int32_t lcs_length(const uint8_t *a, const uint8_t *b, int32_t n) {
    int32_t *prev = malloc((size_t)(n + 1) * sizeof(int32_t));
    int32_t *curr = malloc((size_t)(n + 1) * sizeof(int32_t));
    for (int32_t j = 0; j <= n; j++) prev[j] = 0;

    for (int32_t i = 1; i <= n; i++) {
        curr[0] = 0;
        for (int32_t j = 1; j <= n; j++) {
            if (a[i - 1] == b[j - 1]) {
                curr[j] = prev[j - 1] + 1;
            } else {
                curr[j] = max_i32(prev[j], curr[j - 1]);
            }
        }
        int32_t *tmp = prev;
        prev = curr;
        curr = tmp;
    }

    int32_t result = prev[n];
    free(prev);
    free(curr);
    return result;
}

int main(int argc, char **argv) {
    if (argc < 2) {
        fprintf(stderr, "Usage: %s <n>\n", argv[0]);
        return 1;
    }
    int32_t n = (int32_t)strtol(argv[1], NULL, 10);

    if (n <= 0) {
        printf("0\n");
        return 0;
    }

    uint8_t *a = malloc((size_t)n);
    uint8_t *b = malloc((size_t)n);
    fill(a, n, 0);
    fill(b, n, 0x9E3779B9ULL);

    int32_t result = lcs_length(a, b, n);

    free(a);
    free(b);
    printf("%" PRId32 "\n", result);
    return 0;
}
